import bisect
class Solution:
    def findTheDistanceValue(self, arr1, arr2, d):
        arr2.sort()
        count = 0
        for x in arr1:
            pos = bisect.bisect_left(arr2, x - d)
            if pos == len(arr2) or arr2[pos] > x + d:
                count += 1
        return count

